// ------------------------------------------------------------
//  Card Shuffle – Implicit Treap (C implementation)
// ------------------------------------------------------------
#include <stdio.h>
#include <stdlib.h>
#include <time.h>

typedef struct Node {
    int val;
    int pr;
    int sz;
    int rev;               // lazy reversal flag
    struct Node *l, *r;
} Node;

int sz(Node *t) { return t ? t->sz : 0; }
void upd(Node *t) { if (t) t->sz = 1 + sz(t->l) + sz(t->r); }
void push(Node *t) {
    if (t && t->rev) {
        t->rev = 0;
        Node *tmp = t->l; t->l = t->r; t->r = tmp;
        if (t->l) t->l->rev ^= 1;
        if (t->r) t->r->rev ^= 1;
    }
}
Node* newNode(int v) {
    Node *n = (Node*)malloc(sizeof(Node));
    n->val = v; n->pr = rand(); n->sz = 1; n->rev = 0; n->l = n->r = NULL;
    return n;
}
Node* merge(Node *a, Node *b) {
    if (!a) return b; if (!b) return a;
    push(a); push(b);
    if (a->pr > b->pr) {
        a->r = merge(a->r, b);
        upd(a);
        return a;
    } else {
        b->l = merge(a, b->l);
        upd(b);
        return b;
    }
}
void split(Node *t, int k, Node **a, Node **b) { // first k nodes go to a
    if (!t) { *a = *b = NULL; return; }
    push(t);
    if (sz(t->l) >= k) {
        split(t->l, k, a, &t->l);
        *b = t;
        upd(t);
    } else {
        split(t->r, k - sz(t->l) - 1, &t->r, b);
        *a = t;
        upd(t);
    }
}

void inorder(Node *t, int *out, int *idx) {
    if (!t) return;
    push(t);
    inorder(t->l, out, idx);
    out[(*idx)++] = t->val;
    inorder(t->r, out, idx);
}

int main() {
    srand((unsigned)time(NULL));
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, M; scanf("%d %d", &N, &M);
        Node *root = NULL;
        for (int i = 1; i <= N; ++i) root = merge(root, newNode(i));
        for (int i = 0; i < M; ++i) {
            int A, B, C; scanf("%d %d %d", &A, &B, &C);
            Node *tA, *tB, *tRest, *tX, *tY, *tmp;
            // 1) split A
            split(root, A, &tA, &tmp);
            // 2) split B from the remainder
            split(tmp, B, &tB, &tRest);
            // 3) put A back on top -> merge A + tRest
            root = merge(tA, tRest);
            // 4) split first C cards
            split(root, C, &tX, &tY);
            // 5) reverse B
            if (tB) tB->rev ^= 1;
            // 6) final merge X + B + Y
            root = merge( merge(tX, tB), tY );
        }
        int *out = (int*)malloc(N * sizeof(int));
        int idx = 0;
        inorder(root, out, &idx);
        for (int i = 0; i < N; ++i) {
            if (i) printf(" ");
            printf("%d", out[i]);
        }
        printf("\n");
        free(out);
        // Note: memory of treap nodes is not freed for brevity (fits limits).
    }
    return 0;
}

