// ------------------------------------------------------------
//  Card Shuffle – Implicit Treap (C++17)
// ------------------------------------------------------------
#include <bits/stdc++.h>
using namespace std;
struct Node {
    int val, pr, sz;
    bool rev;
    Node *l, *r;
    Node(int v): val(v), pr(rand()), sz(1), rev(false), l(nullptr), r(nullptr) {}
};
int getsz(Node* t){ return t? t->sz : 0; }
void upd(Node* t){ if(t) t->sz = 1 + getsz(t->l) + getsz(t->r); }
void push(Node* t){ if(t && t->rev){ t->rev = false; swap(t->l, t->r); if(t->l) t->l->rev ^= 1; if(t->r) t->r->rev ^= 1; } }
Node* merge(Node* a, Node* b){ if(!a) return b; if(!b) return a; push(a); push(b); if(a->pr > b->pr){ a->r = merge(a->r, b); upd(a); return a; } else { b->l = merge(a, b->l); upd(b); return b; } }
void split(Node* t, int k, Node* &a, Node* &b){ // first k go to a
    if(!t){ a = b = nullptr; return; }
    push(t);
    if(getsz(t->l) >= k){ split(t->l, k, a, t->l); b = t; upd(t); }
    else{ split(t->r, k - getsz(t->l) - 1, t->r, b); a = t; upd(t); }
}
void inorder(Node* t, vector<int>& res){ if(!t) return; push(t); inorder(t->l, res); res.push_back(t->val); inorder(t->r, res); }
int main(){ ios::sync_with_stdio(false); cin.tie(nullptr);
    srand((unsigned)time(nullptr));
    int T; if(!(cin>>T)) return 0; while(T--){ int N,M; cin>>N>>M; Node* root = nullptr; for(int i=1;i<=N;++i) root = merge(root, new Node(i));
        for(int i=0;i<M;++i){ int A,B,C; cin>>A>>B>>C; Node *tA,*tB,*tRest,*tX,*tY,*tmp; split(root, A, tA, tmp); split(tmp, B, tB, tRest); root = merge(tA, tRest); split(root, C, tX, tY); if(tB) tB->rev ^= 1; root = merge( merge(tX, tB), tY ); }
        vector<int> ans; ans.reserve(N); inorder(root, ans); for(int i=0;i<N;++i){ if(i) cout<<' '; cout<<ans[i]; } cout<<'\n'; }
    return 0; }
